It looks like the problem is the implementation of `overflow`:

```c++
    int overflow(int c) {
        if (!traits_type::eq_int_type(c, traits_type::eof())) {
            *pptr() = traits_type::to_char_type(c);
            pbump(1);
        }
        return sync() ? traits_type::not_eof(c) : traits_type::eof();
    }
```

`sync()` returns `0` on _success_, which is interpreted as failure here. Writing `return sync() == 0 ? traits_type::not_eof(c) : traits_type::eof();` fixes this.

The reason for the template approach for enable/disabling rather than the old-school approach is that it isn't affected by header include order.  With the #define, this won't work:

#include <pybind11/pybind11.h>
#include <pybind11/implicit.h>

which seems undesirable.

I've pushed a sketch of how pybind11 'const' support could work here: https://github.com/wjakob/pybind11/commit/6491cf25139054cce652ed23112ef15f26dee230.

The change introduces a per-instance ``const_`` flag as well as checks which detect violations during casts. Example usage:
```cpp
#include <pybind11/pybind11.h>

namespace py = pybind11;

struct Pet {
    Pet(const std::string &name) : name(name) { }
    void set_name(const std::string &name_) { name = name_; }
    const std::string &get_name() const { return name; }

    std::string name;
};

struct PetShop {
    Pet &polly() { return polly_; }
    const Pet &polly_const() const { return polly_; }

    Pet polly_{"polly"};
};

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 example plugin");

    py::class_<Pet>(m, "Pet")
        .def(py::init<const std::string &>())
        .def("set_name", &Pet::set_name)
        .def("name", &Pet::get_name);

    py::class_<PetShop>(m, "PetShop")
        .def(py::init<>())
        .def("polly", &PetShop::polly, py::return_value_policy::reference_internal)
        .def("polly_const", &PetShop::polly_const, py::return_value_policy::reference_internal);

    return m.ptr();
}
```
